// Parse incoming WhatsApp message from Twilio
const body = $json['Body'] || $json['body'] || '';
const from = $json['From'] || $json['from'] || '';
return [{
  message: body,
  phone: from.replace('whatsapp:', ''),
  raw: $json
}];

// Build prompt for Mistral
const userMsg = $json['message'];
const phone = $json['phone'];
const userContext = $json['data'] || {};
const history = userContext.history || [];
const name = userContext.name || null;
const firstTime = !userContext.history;

// Detect language (simple heuristic)
function detectLang(text) {
  if (/^[�-]*$/.test(text)) return 'English';
  if (/[À-ſ]/.test(text)) return 'Spanish';
  if (/[Ѐ-ӿ]/.test(text)) return 'Russian';
  // fallback
  return 'English';
}
const lang = detectLang(userMsg);

let systemPrompt = `You are a friendly, empathetic WhatsApp mood companion bot. Respond concisely, use emojis, and keep answers short. Detect the user's mood from their message and adapt your reply. If the user is sad, comfort them; if happy, share enthusiasm. If they ask for a joke, fun fact, or suggestion, provide one. Occasionally suggest a simple activity based on mood. If you know the user's name, use it. Reply in the user's language: ${lang}.`;
if (firstTime) {
  systemPrompt += ' Greet the user and ask how they are feeling.';
}

// Build conversation history for context
const messages = [
  { role: 'system', content: systemPrompt }
];
if (history && Array.isArray(history)) {
  for (let h of history.slice(-4)) {
    messages.push(h);
  }
}
messages.push({ role: 'user', content: userMsg });

return [{
  phone,
  name,
  firstTime,
  messages,
  userMsg,
  lang,
  userContext
}];

// Parse Mistral response and update context
const reply = $json.choices?.[0]?.message?.content || 'Sorry, I could not process your request right now.';
const phone = $node["Build Prompt"]["json"]["phone"];
const name = $node["Build Prompt"]["json"]["name"];
const userMsg = $node["Build Prompt"]["json"]["userMsg"];
const lang = $node["Build Prompt"]["json"]["lang"];
const userContext = $node["Build Prompt"]["json"]["userContext"];
const history = userContext.history || [];
const newHistory = [...history.slice(-3), { role: 'user', content: userMsg }, { role: 'assistant', content: reply }];
return [{
  phone,
  name,
  reply,
  lang,
  context: {
    ...userContext,
    history: newHistory
  }
}];
